func (s *financialServiceServer) CreateTransaction(ctx context.Context, req *pb.TransactionRequest) (*pb.TransactionResponse, error) {
	log.Printf("Received CreateTransaction request: %v", req)

	// Simulate some processing time
	time.Sleep(100 * time.Millisecond)

	s.mu.Lock()
	defer s.mu.Unlock()

	var transactionStatus pb.TransactionStatus = pb.TransactionStatus_FAILED
	var message string

	senderAccount, senderExists := s.accounts[req.SenderAccountId]
	receiverAccount, receiverExists := s.accounts[req.ReceiverAccountId]

	if req.Amount <= 0 {
		message = "Transaction amount must be positive."
		log.Printf("Transaction failed: %s", message)
		return &pb.TransactionResponse{
			TransactionId: req.TransactionId,
			Status:        transactionStatus,
			Message:       message,
		}, nil
	}

	switch req.Type {
	case pb.TransactionType_DEPOSIT:
		if !receiverExists {
			message = fmt.Sprintf("Receiver account '%s' not found.", req.ReceiverAccountId)
			break
		}
		if receiverAccount.Currency != req.Currency {
			message = fmt.Sprintf("Currency mismatch for deposit. Account '%s' expects %s, but received %s.",
				req.ReceiverAccountId, receiverAccount.Currency, req.Currency)
			break
		}
		receiverAccount.Balance += req.Amount
		transactionStatus = pb.TransactionStatus_COMPLETED
		message = fmt.Sprintf("Deposit of %.2f %s to account %s completed.", req.Amount, receiverAccount.Currency, req.ReceiverAccountId)

	case pb.TransactionType_WITHDRAWAL:
		if !senderExists {
			message = fmt.Sprintf("Sender account '%s' not found.", req.SenderAccountId)
			break
		}
		if senderAccount.Currency != req.Currency {
			message = fmt.Sprintf("Currency mismatch for withdrawal. Account '%s' expects %s, but received %s.",
				req.SenderAccountId, senderAccount.Currency, req.Currency)
			break
		}
		if senderAccount.Balance < req.Amount {
			message = fmt.Sprintf("Insufficient funds in account '%s'. Available: %.2f %s, Requested: %.2f %s",
				req.SenderAccountId, senderAccount.Balance, senderAccount.Currency, req.Amount, req.Currency)
			break
		}
		senderAccount.Balance -= req.Amount
		transactionStatus = pb.TransactionStatus_COMPLETED
		message = fmt.Sprintf("Withdrawal of %.2f %s from account %s completed.", req.Amount, senderAccount.Currency, req.SenderAccountId)

	case pb.TransactionType_TRANSFER:
		if !senderExists {
			message = fmt.Sprintf("Sender account '%s' not found.", req.SenderAccountId)
			break
		}
		if !receiverExists {
			message = fmt.Sprintf("Receiver account '%s' not found.", req.ReceiverAccountId)
			break
		}
		if req.SenderAccountId == req.ReceiverAccountId {
			message = "Cannot transfer to the same account."
			break
		}
		if senderAccount.Currency != receiverAccount.Currency {
			message = fmt.Sprintf("Currency mismatch: sender (%s) and receiver (%s) accounts have different currencies.",
				senderAccount.Currency, receiverAccount.Currency)
			break
		}
		if senderAccount.Currency != req.Currency {
			message = fmt.Sprintf("Currency mismatch for transfer. Sender account '%s' expects %s, but received %s.",
				req.SenderAccountId, senderAccount.Currency, req.Currency)
			break
		}
		if senderAccount.Balance < req.Amount {
			message = fmt.Sprintf("Insufficient funds in sender account '%s'. Available: %.2f %s, Requested: %.2f %s",
				req.SenderAccountId, senderAccount.Balance, senderAccount.Currency, req.Amount, req.Currency)
			break
		}

		senderAccount.Balance -= req.Amount
		receiverAccount.Balance += req.Amount
		transactionStatus = pb.TransactionStatus_COMPLETED
		message = fmt.Sprintf("Transfer of %.2f %s from %s to %s completed.", req.Amount, senderAccount.Currency, req.SenderAccountId, req.ReceiverAccountId)

	default:
		message = fmt.Sprintf("Unsupported transaction type: %v", req.Type)
	}

	if transactionStatus == pb.TransactionStatus_FAILED && message == "" {
		message = "An unknown error occurred during transaction processing."
	}

	log.Printf("Transaction %s: %s (Status: %v)", req.TransactionId, message, transactionStatus)
	return &pb.TransactionResponse{
		TransactionId: req.TransactionId,
		Status:        transactionStatus,
		Message:       message,
	}, nil
}

func (s *financialServiceServer) GetBalance(ctx context.Context, req *pb.BalanceRequest) (*pb.BalanceResponse, error) {
	log.Printf("Received GetBalance request for account: %s", req.AccountId)

	// Simulate some processing time
	time.Sleep(50 * time.Millisecond)

	s.mu.RLock()
	defer s.mu.RUnlock()

	account, exists := s.accounts[req.AccountId]
	if !exists {
		log.Printf("Account '%s' not found.", req.AccountId)
		return &pb.BalanceResponse{
			AccountId: req.AccountId,
			Balance:   0,
			Currency:  "",
			Status:    pb.BalanceStatus_ACCOUNT_NOT_FOUND,
			Message:   fmt.Sprintf("Account '%s' not found.", req.AccountId),
		}, nil
	}

	log.Printf("Balance for account '%s': %.2f %s", req.AccountId, account.Balance, account.Currency)
	return &pb.BalanceResponse{
		AccountId: req.AccountId,
		Balance:   account.Balance,
		Currency:  account.Currency,
		Status:    pb.BalanceStatus_OK,
		Message:   "Balance retrieved successfully.",
	}, nil
}

